INSERT INTO `announcement` VALUES (1,'欢迎来到母婴乐园商城','亲爱的用户，欢迎来到母婴乐园商城！我们精选全球优质母婴用品，为您和宝宝提供最好的产品和服务。新用户注册即享9折优惠！',1,1,'2025-01-15 09:00:00','2025-01-15 09:00:00','2026-03-13 22:33:17',0),(2,'春季大促活动开启','春暖花开，母婴乐园春季大促正式开始！全场奶粉满300减30，纸尿裤买三送一，更多优惠等你来发现。活动时间：3月1日-3月31日。',2,1,'2025-03-01 00:00:00','2025-02-28 15:00:00','2026-03-13 22:33:17',0),(3,'系统升级通知','为提升用户体验，我们将于2025年4月1日凌晨2:00-4:00进行系统升级维护，届时部分功能可能暂时不可用，请您提前做好准备。给您带来的不便，深表歉意。',3,1,'2025-03-28 10:00:00','2025-03-28 10:00:00','2026-03-13 22:33:17',0),(4,'618年中盛典预告','一年一度的618年中大促即将开启！母婴乐园准备了超多惊喜：满减优惠、限时秒杀、新客专享礼包……敬请期待！',2,1,'2025-05-20 09:00:00','2025-05-20 09:00:00','2026-03-13 22:33:17',0),(5,'新品上架：有机辅食系列','母婴乐园新引进多款有机辅食产品，包括有机米粉、有机果泥、有机面条等，全部通过国家有机认证，为宝宝的每一口把关。',1,1,'2025-04-15 10:00:00','2025-04-15 10:00:00','2026-03-13 22:33:17',0),(6,'API测试公告(已编辑)','内容已更新',1,1,'2026-03-13 22:43:00','2026-03-13 22:43:00','2026-03-13 22:43:00',1),(7,'API测试公告','这是一条测试公告内容',1,1,'2026-03-13 22:55:38','2026-03-13 22:55:38','2026-03-13 22:55:38',0);
