INSERT INTO `review` VALUES (22,2,1,1,5,'奶粉很好，宝宝很爱喝，冲泡不挂壁，一直在买这个牌子的。推荐给所有妈妈！',NULL,1,'2025-03-06 10:00:00','2026-03-13 23:53:06',0),(23,6,1,6,5,'一直回购的奶粉，飞鹤品质值得信赖，奶粉溶解度好，口味清淡。',NULL,1,'2025-03-20 11:00:00','2026-03-13 23:53:06',0),(24,2,1,15,5,'第三次购买了，品质稳定，宝宝适应得很好，物流也快。',NULL,1,'2025-04-15 10:00:00','2026-03-13 23:53:06',0),(25,10,1,22,4,'奶粉口味清淡，宝宝容易接受，性价比不错。就是盖子不太好打开。',NULL,1,'2025-05-03 16:00:00','2026-03-13 23:53:06',0),(26,4,1,3,5,'国产奶粉之光！宝宝从一段喝到三段了，营养全面，绝对放心。',NULL,1,'2025-03-13 09:30:00','2026-03-13 23:53:06',0),(27,3,2,2,5,'朋友推荐的这款奶粉，营养成分很全面，宝宝喝了之后肠胃一直很好。',NULL,1,'2025-03-10 14:00:00','2026-03-13 23:53:06',0),(28,5,2,5,4,'奶粉溶解性不错，但价格偏贵，趁活动囤了几罐。',NULL,1,'2025-03-15 16:00:00','2026-03-13 23:53:06',0),(29,7,2,7,5,'宝宝从母乳过渡到奶粉，选了爱他美，适应得很好，没有上火。',NULL,1,'2025-03-20 10:00:00','2026-03-13 23:53:06',0),(30,2,2,8,4,'包装精美，奶粉细腻，就是量有点少，感觉不太耐吃。',NULL,1,'2025-03-25 11:30:00','2026-03-13 23:53:06',0),(31,4,3,3,5,'荷兰原装进口，品质有保障，宝宝第一口奶选的就是这个。',NULL,1,'2025-03-13 16:00:00','2026-03-13 23:53:06',0),(32,6,3,6,4,'奶粉还不错，但感觉溶解度一般，需要多摇几下。',NULL,1,'2025-03-22 14:00:00','2026-03-13 23:53:06',0),(33,8,3,14,5,'新生儿用这款很好，不容易上火，大便也正常。',NULL,1,'2025-04-10 09:00:00','2026-03-13 23:53:06',0),(34,2,4,15,5,'米粉细腻，容易冲调，宝宝第一次吃辅食就选的这款，很满意。',NULL,1,'2025-04-15 10:15:00','2026-03-13 23:53:06',0),(35,4,4,10,5,'有机认证的米粉，给宝宝吃放心，口感细滑，宝宝很配合。',NULL,1,'2025-03-26 10:00:00','2026-03-13 23:53:06',0),(36,7,4,13,4,'米粉质量不错，就是包装设计不太方便取用。',NULL,1,'2025-04-10 15:30:00','2026-03-13 23:53:06',0),(37,3,4,9,5,'宝宝六个月开始添加辅食，这款米粉非常适合，铁含量高。',NULL,1,'2025-03-23 09:00:00','2026-03-13 23:53:06',0),(38,6,5,12,4,'果泥口味不错，宝宝很喜欢，方便携带，就是分量有点少。',NULL,1,'2025-04-08 11:00:00','2026-03-13 23:53:06',0),(39,2,5,8,5,'纯水果制作，没有添加剂，外出带很方便，宝宝每次都吃光光。',NULL,1,'2025-03-26 14:00:00','2026-03-13 23:53:06',0),(40,5,5,11,4,'味道很好，苹果香蕉味宝宝最爱，不过有点偏甜。',NULL,1,'2025-04-07 16:00:00','2026-03-13 23:53:06',0),(41,4,6,3,4,'纸尿裤质量不错，透气性好，但是价格稍贵，趁活动多囤几包。',NULL,1,'2025-03-13 16:00:00','2026-03-13 23:53:06',0),(42,2,6,1,5,'花王一直是我们家首选，柔软透气，从来不会红屁屁。',NULL,1,'2025-03-07 10:00:00','2026-03-13 23:53:06',0),(43,5,6,5,5,'日本原装进口品质就是好，宝宝穿了整晚都不漏。',NULL,1,'2025-03-16 08:00:00','2026-03-13 23:53:06',0),(44,7,6,7,4,'整体不错，就是腰围弹力感觉稍微有点松。',NULL,1,'2025-03-21 09:30:00','2026-03-13 23:53:06',0),(45,10,6,22,5,'性价比最高的进口纸尿裤，吸水性很强，推荐！',NULL,1,'2025-05-04 10:00:00','2026-03-13 23:53:06',0),(46,3,7,9,4,'超薄设计确实很好，宝宝活动自如，透气性也不错。',NULL,1,'2025-03-23 15:00:00','2026-03-13 23:53:06',0),(47,6,7,6,5,'好奇铂金装真的很薄，夏天用特别好，不会闷热。',NULL,1,'2025-03-21 13:00:00','2026-03-13 23:53:06',0),(48,4,7,10,4,'吸水量不错，就是码子偏小，建议买大一号。',NULL,1,'2025-03-27 11:00:00','2026-03-13 23:53:06',0),(49,2,9,8,4,'玻璃奶瓶手感不错，刻度清晰，只是比较重，外出携带不太方便。',NULL,1,'2025-03-25 10:00:00','2026-03-13 23:53:06',0),(50,3,9,9,5,'贝亲的奶瓶品质一直很好，宝宝很快就适应了，不抗拒。',NULL,1,'2025-03-24 14:00:00','2026-03-13 23:53:06',0),(51,5,9,11,5,'第三代奶嘴设计确实好，接近母乳感觉，宝宝吃得很好。',NULL,1,'2025-04-08 09:00:00','2026-03-13 23:53:06',0),(52,8,9,14,4,'做工精细，但玻璃的确实要小心，摔了一个心疼。',NULL,1,'2025-04-11 15:00:00','2026-03-13 23:53:06',0),(53,2,11,4,5,'吸奶器很好用，双边同时吸效率很高，用起来也很舒适，推荐新手妈妈购买。',NULL,1,'2025-03-16 09:00:00','2026-03-13 23:53:06',0),(54,4,11,10,5,'虽然价格贵了点，但真的好用，吸力均匀不疼，产奶量明显增加。',NULL,1,'2025-03-28 10:00:00','2026-03-13 23:53:06',0),(55,6,11,12,4,'医院级品质，用起来很放心，就是噪音稍微有点大。',NULL,1,'2025-04-09 11:00:00','2026-03-13 23:53:06',0),(56,2,12,8,5,'宝宝洗发沐浴露很温和，泡沫细腻，洗完皮肤滑滑的，没有刺激。',NULL,1,'2025-03-25 10:10:00','2026-03-13 23:53:06',0),(57,3,12,9,5,'无泪配方真的不辣眼睛，宝宝洗澡再也不哭了。',NULL,1,'2025-03-24 15:00:00','2026-03-13 23:53:06',0),(58,5,12,18,4,'味道清香，泡沫丰富，就是瓶口设计不太好按压。',NULL,1,'2025-04-23 11:00:00','2026-03-13 23:53:06',0),(59,7,12,13,5,'用了好几瓶了，一直回购，性价比很高的宝宝洗护用品。',NULL,1,'2025-04-10 16:00:00','2026-03-13 23:53:06',0),(60,7,16,13,5,'摇铃颜色鲜艳，做工精细，没有异味，宝宝拿到手就不放下了。',NULL,1,'2025-04-10 15:00:00','2026-03-13 23:53:06',0),(61,2,16,29,5,'费雪的玩具品质一如既往的好，设计安全，宝宝很喜欢咬牙胶。',NULL,1,'2025-05-20 15:00:00','2026-03-13 23:53:06',0),(62,4,16,10,4,'宝宝三个月开始玩，锻炼手部抓握很好用，颜色也好看。',NULL,1,'2025-03-28 14:00:00','2026-03-13 23:53:06',0),(63,7,17,7,5,'乐高得宝积木安全无棱角，宝宝玩得很开心，还能认识动物。',NULL,1,'2025-03-22 10:00:00','2026-03-13 23:53:06',0),(64,3,17,9,4,'大颗粒设计不用担心误吞，颜色鲜艳，但价格偏贵。',NULL,1,'2025-03-24 16:00:00','2026-03-13 23:53:06',0),(65,5,17,11,5,'送给侄子的生日礼物，非常喜欢，做工精良。',NULL,1,'2025-04-08 14:00:00','2026-03-13 23:53:06',0),(66,5,18,11,5,'推车质量很好，高景观设计宝宝坐着更安全，折叠也很方便，出门必带。',NULL,1,'2025-04-07 14:00:00','2026-03-13 23:53:06',0),(67,2,18,4,4,'推车整体不错，就是有点重，上下楼梯不太方便。',NULL,1,'2025-03-16 16:00:00','2026-03-13 23:53:06',0),(68,7,18,7,5,'一键折叠真的很方便，放后备箱轻松，宝宝坐着也很舒适。',NULL,1,'2025-03-22 11:00:00','2026-03-13 23:53:06',0),(69,4,26,25,5,'山茶油霜效果很好，宝宝红屁屁涂了两天就好了，强烈推荐！',NULL,1,'2025-05-10 10:00:00','2026-03-13 23:53:06',0),(70,2,26,23,5,'冬天宝宝皮肤容易干裂，用了这个保湿效果非常好。',NULL,1,'2025-05-07 09:00:00','2026-03-13 23:53:06',0),(71,6,26,27,4,'质地温和不油腻，但感觉用量比较大，一管用得比较快。',NULL,1,'2025-05-16 14:00:00','2026-03-13 23:53:06',0),(72,7,30,20,5,'安全座椅非常稳固，ISOFIX安装很方便，宝宝坐着很舒服，360度旋转上下车很方便。',NULL,1,'2025-04-29 14:00:00','2026-03-13 23:53:06',0),(73,5,30,11,5,'德国品牌品质没话说，虽然价格贵但安全无价，强烈推荐！',NULL,1,'2025-04-08 15:00:00','2026-03-13 23:53:06',0),(74,2,30,15,4,'座椅做工精细，面料柔软，就是安装过程相对复杂，需要仔细看说明书。',NULL,1,'2025-04-16 10:00:00','2026-03-13 23:53:06',0),(75,6,13,27,4,'保湿效果不错，涂上不油腻，适合宝宝日常使用。',NULL,1,'2025-05-15 11:00:00','2026-03-13 23:53:06',0),(76,2,13,8,5,'给宝宝用了一个冬天，皮肤一直滑滑嫩嫩的，强推！',NULL,1,'2025-03-26 10:30:00','2026-03-13 23:53:06',0),(77,4,13,10,4,'温和无刺激，但保湿持久度一般，需要多涂几次。',NULL,1,'2025-03-28 15:00:00','2026-03-13 23:53:06',0),(78,2,25,23,4,'PPSU材质比玻璃的轻很多，适合外出，奶嘴设计也合理。',NULL,1,'2025-05-06 14:00:00','2026-03-13 23:53:06',0),(79,3,25,24,5,'NUK的奶嘴仿真度很高，宝宝接受度好，不会混淆母乳和奶瓶。',NULL,1,'2025-05-04 10:00:00','2026-03-13 23:53:06',0),(80,5,25,26,4,'奶瓶质量不错，就是300ml对小月龄宝宝来说有点大。',NULL,1,'2025-05-10 16:00:00','2026-03-13 23:53:06',0),(81,6,29,19,5,'待产包内容很齐全，省去了自己一样一样买的麻烦，性价比很高。',NULL,1,'2025-04-22 11:00:00','2026-03-13 23:53:06',0),(82,2,29,15,4,'大部分物品质量不错，但牙刷和梳子感觉比较一般。',NULL,1,'2025-04-16 14:00:00','2026-03-13 23:53:06',0),(83,4,29,10,5,'新手妈妈必备神器，包含了入院需要的几乎所有东西，买了不后悔！',NULL,1,'2025-03-29 09:00:00','2026-03-13 23:53:06',0),(84,5,32,18,5,'精准控温真的太方便了，半夜起来冲奶不用等水凉，强推！',NULL,1,'2025-04-24 10:00:00','2026-03-13 23:53:06',0),(85,2,32,1,4,'控温很准确，但1.2L容量感觉偏小，一天要加两次水。',NULL,1,'2025-03-07 14:00:00','2026-03-13 23:53:06',0),(86,7,32,20,5,'新手爸妈的救星，再也不用温度计测水温了，操作简单。',NULL,1,'2025-04-30 09:00:00','2026-03-13 23:53:06',0);
